(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["NoticeBanner"],{"0e89":function(a,t,c){"use strict";c.r(t);var n=c("7a23");const e={class:"banner-wrapper"},s=Object(n["createStaticVNode"])('<div class="banner-content" data-v-0c446803><div class="title-wrapper" data-v-0c446803><div class="banner-title" data-v-0c446803>重要通知</div><div class="title-sub" data-v-0c446803>应用商店调整计划公告</div></div><div class="banner-text" data-v-0c446803><p class="para-content" data-v-0c446803> 尊敬的学习机用户： </p><p class="para-content" data-v-0c446803> 您好！<br data-v-0c446803>感谢您一直以来对学而思学习机的支持与信任。我们一直致力于为广大用户提供安全、便捷、全面的第三方应用使用体验，以满足多样的学习机使用需求。 </p><p class="para-content" data-v-0c446803> 根据《中华人民共和国反电信网络诈骗法》《互联网信息服务管理办法》（国务院令第292号）等法律法规要求，工业和信息化部组织网络接入服务提供者、分发平台、智能终端生产企业开展移动互联网的应用备案工作。 </p><p class="para-content" data-v-0c446803> 依照相关要求，移动应用软件预置与分发服务提供者【应】拒绝上架未备案应用，共同维护用户权益，旨在保护用户的合法权益，防止恶意软件和病毒的传播。 </p><p class="para-content" data-v-0c446803> 为了更好地维护您的权益，我们将会在2024年4月1日，对学习机的应用市场进行升级，届时尚未完成APP应用备案的应用将会无法进行下载、安装、更新。 </p><p class="para-content" data-v-0c446803> 为了确保您的学习机使用不受影响，我们将督促相关APP开发者尽快完成应用备案的要求，也将持续关注备案进度，并尽力为您提供及时、准确的信息更新。学而思学习机应用商店将一如既往地为您提供优质的服务，让您在学习上更加便捷、高效。 </p><p class="para-content" data-v-0c446803> 再次感谢您的理解与配合，如有任何疑问或建议，请随时与我们联系。我们将竭诚为您服务，让您在使用学习机的过程中无后顾之忧。 </p><p class="para-content right-text" data-v-0c446803> 学而思学习机应用商店<br data-v-0c446803>2024年02月01日 </p></div></div><div class="bg-img" data-v-0c446803></div>',2),d=[s];var p=Object(n["defineComponent"])({__name:"NoticeBanner",setup(a){return(a,t)=>(Object(n["openBlock"])(),Object(n["createElementBlock"])("div",e,d))}}),v=(c("741b"),c("d959")),r=c.n(v);const i=r()(p,[["__scopeId","data-v-0c446803"]]);t["default"]=i},"741b":function(a,t,c){"use strict";c("99c9")},"99c9":function(a,t,c){}}]);
